#!/usr/bin/env node
// Sync design tokens from the sibling boston-ar project into this app.
// Idempotent: overwrites the generated file each time.

import { readFileSync, writeFileSync, existsSync, mkdirSync } from 'node:fs'
import { dirname, resolve } from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = dirname(fileURLToPath(import.meta.url))
const SOURCE = 'C:\\Users\\gh0t\\Desktop\\boston-ar\\app\\globals.css'
const TARGET = resolve(__dirname, '..', 'app', '_generated-boston-tokens.css')

function extractBlock(src, startMarker, endMarker) {
  const start = src.indexOf(startMarker)
  if (start === -1) return null
  const end = src.indexOf(endMarker, start)
  if (end === -1) return null
  return src.slice(start, end + endMarker.length)
}

function main() {
  if (!existsSync(SOURCE)) {
    console.warn(`[sync] WARNING: source not found: ${SOURCE}`)
    process.exit(0)
  }
  const src = readFileSync(SOURCE, 'utf8')

  const rootBlock = extractBlock(src, ':root {', '}')
  const cardBlock = extractBlock(src, '.boston-card {', '}')

  const parts = [
    '/* AUTO-GENERATED by scripts/sync-from-boston-ar.mjs — do not edit by hand. */',
    `/* Source: ${SOURCE} */`,
    '',
  ]
  if (rootBlock) parts.push('/* :root tokens from boston-ar */', rootBlock, '')
  else parts.push('/* (no :root block found in source) */', '')
  if (cardBlock) parts.push('/* .boston-card from boston-ar */', cardBlock, '')
  else parts.push('/* (no .boston-card block found in source) */', '')

  mkdirSync(dirname(TARGET), { recursive: true })
  writeFileSync(TARGET, parts.join('\n'), 'utf8')
  console.log(`[sync] Wrote ${TARGET}`)
  console.log(`[sync]   :root block: ${rootBlock ? 'yes' : 'no'}`)
  console.log(`[sync]   .boston-card block: ${cardBlock ? 'yes' : 'no'}`)
}

main()
